INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2023/09/22 14:59:59", 0.0, "2023/06/30 12:00:00", "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 1.47, 126401, 10001, "クローチェ", 1, 1, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2023/09/22 14:59:59", 0.0, "2023/06/30 12:00:00", "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2.15, 126401, 10002, "クローチェ", 2, 1, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2023/09/22 14:59:59", 0.0, "2023/06/30 12:00:00", "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 0.0, 126501, 10003, "ライラエル", 1, 1, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2023/09/22 14:59:59", 0.0, "2023/06/30 12:00:00", "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 0.0, 126501, 10004, "ライラエル", 2, 1, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2023/12/22 14:59:59", 0.0, "2023/09/15 15:00:00", "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 0.0, 127702, 10005, "リンド", 1, 2, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2023/12/22 14:59:59", 0.0, "2023/09/15 15:00:00", "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 0.0, 127702, 10006, "リンド", 2, 2, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2023/12/22 14:59:59", 0.0, "2023/09/15 15:00:00", "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 0.0, 127802, 10007, "ヴルム", 1, 2, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2023/12/22 14:59:59", 0.0, "2023/09/15 15:00:00", "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 6.5, 127802, 10008, "ヴルム", 2, 2, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/03/22 14:59:59", 0.0, "2023/12/15 15:00:00", "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 0.0, 129602, 10009, "アネモネ", 1, 3, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/03/22 14:59:59", 0.0, "2023/12/15 15:00:00", "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 0.0, 129602, 10010, "アネモネ", 2, 3, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/03/22 14:59:59", 0.0, "2023/12/15 15:00:00", "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 0.0, 129701, 10011, "ネフィ=ネラ", 1, 3, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/03/22 14:59:59", 0.0, "2023/12/15 15:00:00", "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 6.2, 129701, 10012, "ネフィ=ネラ", 2, 3, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 5, "2024/06/22 14:59:59", 0.0, "2024/03/15 15:00:00", "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 3.1, 130301, 10013, "カノン", 1, 4, 3, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2024/06/22 14:59:59", 0.0, "2024/03/15 15:00:00", "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 6.15, 130301, 10014, "カノン", 2, 4, 3, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2024/06/22 14:59:59", 0.0, "2024/03/15 15:00:00", "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 0.0, 130401, 10015, "ナーナ", 1, 4, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/06/22 14:59:59", 0.0, "2024/03/15 15:00:00", "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 3.35, 130401, 10016, "ナーナ", 2, 4, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/09/22 14:59:59", 0.0, "2024/06/15 15:00:00", "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 0.0, 130502, 10017, "ホウオウ", 1, 5, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/09/22 14:59:59", 0.0, "2024/06/15 15:00:00", "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 3.18, 130502, 10018, "ホウオウ", 2, 5, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 4, "2024/09/22 14:59:59", 0.0, "2024/06/15 15:00:00", "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 0.0, 130503, 10019, "ホウオウ", 3, 5, 4, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2024/09/22 14:59:59", 0.0, "2024/06/15 15:00:00", "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 4.9, 123301, 10020, "ネア", 1, 5, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2024/09/22 14:59:59", 0.0, "2024/06/15 15:00:00", "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 4.8, 123301, 10021, "ネア", 2, 5, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/12/22 14:59:59", 0.0, "2024/09/15 15:00:00", "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 4.922, 133301, 10022, "カリザ", 1, 6, 3, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 5, "2024/12/22 14:59:59", 0.0, "2024/09/15 15:00:00", "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 9.638, 133301, 10023, "カリザ", 2, 6, 3, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2024/12/22 14:59:59", 0.0, "2024/09/15 15:00:00", "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2.88, 133401, 10024, "ミーア", 1, 6, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2024/12/22 14:59:59", 0.0, "2024/09/15 15:00:00", "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 4.818, 133401, 10025, "ミーア", 2, 6, 5, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2025/03/22 14:59:59", 0.0, "2024/12/15 15:00:00", "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 1.78, 133002, 10026, "グレイス", 1, 7, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 7, "2025/03/22 14:59:59", 0.0, "2024/12/15 15:00:00", "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 6.15, 133002, 10027, "グレイス", 2, 7, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2025/03/22 14:59:59", 0.0, "2024/12/15 15:00:00", "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 4.28, 133102, 10028, "ヴァイオレット", 1, 7, 6, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2025/03/22 14:59:59", 0.0, "2024/12/15 15:00:00", "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 0.0, 133102, 10029, "ヴァイオレット", 2, 7, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2025/06/23 14:59:59", 0.0, "2025/03/15 15:00:00", "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 5.53, 136902, 10030, "ルルィ", 1, 8, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 7, "2025/06/23 14:59:59", 0.0, "2025/03/15 15:00:00", "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 6.05, 136902, 10031, "ルルィ", 2, 8, 9, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2025/06/23 14:59:59", 0.0, "2025/03/15 15:00:00", "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 0.0, 137001, 10032, "デュラン", 1, 8, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2025/06/23 14:59:59", 0.0, "2025/03/15 15:00:00", "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 0.0, 137001, 10033, "デュラン", 2, 8, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2025/09/23 14:59:59", 0.0, "2025/06/16 15:00:00", "おう\n好きなもん持ってきな", 0.0, 135902, 10034, "サツキ", 1, 9, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 6, "2025/09/23 14:59:59", 0.0, "2025/06/16 15:00:00", "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 4.935, 135902, 10035, "サツキ", 2, 9, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 5, "2025/09/23 14:59:59", 0.0, "2025/06/16 15:00:00", "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 7.441, 135802, 10036, "ユキノ", 1, 9, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 7, "2025/09/23 14:59:59", 0.0, "2025/06/16 15:00:00", "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 0.0, 135802, 10037, "ユキノ", 2, 9, 7, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2025/12/22 14:59:59", 0.0, "2025/09/16 15:00:00", "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2.295, 130901, 10038, "クルル", 1, 10, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 6, "2025/12/22 14:59:59", 0.0, "2025/09/16 15:00:00", "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 6.281, 130901, 10039, "クルル", 2, 10, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2025/12/22 14:59:59", 0.0, "2025/09/16 15:00:00", "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 5.549, 137701, 10040, "ヴォルガーノ", 1, 10, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 6, "2025/12/22 14:59:59", 0.0, "2025/09/16 15:00:00", "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2.64, 137701, 10041, "ヴォルガーノ", 2, 10, 3, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 4, "2026/03/23 11:59:59", 0.0, "2025/12/15 15:00:00", "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 7.642, 132801, 10042, "ライラエル", 1, 11, 7, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2026/03/23 11:59:59", 0.0, "2025/12/15 15:00:00", "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 0.0, 132802, 10043, "ライラエル", 2, 11, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2026/03/23 11:59:59", 0.0, "2025/12/15 15:00:00", "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 0.0, 134502, 10044, "クローチェ", 1, 11, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2026/03/23 11:59:59", 0.0, "2025/12/15 15:00:00", "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 3.72, 134501, 10045, "クローチェ", 2, 11, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 1, "2026/06/22 11:59:59", 0.0, "2026/03/16 12:00:00", "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 4.991, 138201, 10046, "ネフィ＝ネラ", 1, 12, 2, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 4, "2026/06/22 11:59:59", 0.0, "2026/03/16 12:00:00", "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 3.877, 138201, 10047, "ネフィ＝ネラ", 2, 12, 1, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 6, "2026/06/22 11:59:59", 0.0, "2026/03/16 12:00:00", "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 1.71, 136001, 10048, "アラクネ", 1, 12, 4, 2002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (-470.0, 2, "2026/06/22 11:59:59", 0.0, "2026/03/16 12:00:00", "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 5.32, 136001, 10049, "アラクネ", 2, 12, 5, 2002);
